-- ============================================================================
-- digital-clr-dryrun.sql — 디지털 흑백/칼라 교정 ROLLBACK 전용 DRY-RUN
-- 라이브 무변경(맨끝 ROLLBACK). 교정 전/후 단가행 매칭을 한 트랜잭션 내에서 실증.
-- 실행: psql ... -f digital-clr-dryrun.sql  (자격증명 .env.local RAILWAY_DB_*)
-- ============================================================================

BEGIN;

-- [BEFORE] 현재 라이브: 국4절 단면/양면 qty1 (저청구 상태)
\echo '=== BEFORE (current live) — 국4절 칼라엽서 qty=1 ==='
SELECT print_opt_cd,
       CASE print_opt_cd WHEN 'POPT_000001' THEN '단면' WHEN 'POPT_000002' THEN '양면' END AS sel_side,
       unit_price, note
  FROM t_prc_component_prices
 WHERE comp_cd='COMP_PRINT_DIGITAL_S1' AND plt_siz_cd='SIZ_000499' AND min_qty=1
 ORDER BY print_opt_cd;

-- [APPLY] 교정(치환)
DELETE FROM t_prc_component_prices WHERE comp_cd='COMP_PRINT_DIGITAL_S1';

-- [AFTER] 교정 후: 국4절 단면=4000 / 양면=6000, 3절 단면=4500 / 양면=7000
\echo '=== AFTER (corrected) — 국4절 + 3절 칼라엽서 qty=1 ==='
SELECT plt_siz_cd,
       CASE plt_siz_cd WHEN 'SIZ_000499' THEN '국4절' WHEN 'SIZ_000077' THEN '3절' END AS plate,
       print_opt_cd,
       CASE print_opt_cd WHEN 'POPT_000001' THEN '단면' WHEN 'POPT_000002' THEN '양면' END AS sel_side,
       unit_price, note
  FROM t_prc_component_prices
 WHERE comp_cd='COMP_PRINT_DIGITAL_S1' AND min_qty=1
 ORDER BY plt_siz_cd, print_opt_cd;

-- [GUARD] 이중합산/모호매칭 가드: 같은 (comp,plt,popt,proc,min_qty) 조합 중복이 0이어야.
\echo '=== GUARD: duplicate natural-key combos (must be 0) ==='
SELECT plt_siz_cd, print_opt_cd, min_qty, count(*) AS n
  FROM t_prc_component_prices
 WHERE comp_cd='COMP_PRINT_DIGITAL_S1'
 GROUP BY 1,2,3 HAVING count(*) > 1;

-- [GUARD] S2 미배선 死comp 보존 확인(교정이 S2 를 건드리지 않음 → 이중합산원 부재)
\echo '=== GUARD: S2 rows untouched (still dead, no formula binds them) ==='
SELECT 'S2_rows' AS k, count(*) FROM t_prc_component_prices WHERE comp_cd='COMP_PRINT_DIGITAL_S2'
UNION ALL
SELECT 'S2_formula_bindings', count(*) FROM t_prc_formula_components WHERE comp_cd='COMP_PRINT_DIGITAL_S2';

-- [COUNT] 교정 후 S1 행수 = 212(칼라 단면106 + 양면106)
\echo '=== row count after fix (expect 212) ==='
SELECT count(*) AS s1_rows FROM t_prc_component_prices WHERE comp_cd='COMP_PRINT_DIGITAL_S1';

ROLLBACK;
\echo '=== ROLLBACK done — 라이브 무변경 ==='
